CREATE POLICY "Users can update tasks in shared projects"
ON public.tasks
FOR UPDATE
USING (
  project_id IS NOT NULL AND
  EXISTS (
    SELECT 1 FROM public.shared_project_members spm
    WHERE spm.project_id = tasks.project_id AND spm.user_id = auth.uid()
  )
);

